def get_credential():
    """
    Get Azure credential using Managed Identity.
    
    SECURITY NOTE: This MVP uses broad permissions for rapid development.
    For production, follow the principle of least privilege:
    - Storage: Use 'Storage Blob Data Reader' instead of 'Storage Blob Data Contributor'
      if only reading blobs.
    - Cosmos DB: Use a custom role with only read/write on specific containers
      instead of 'Cosmos DB Account Contributor' (which grants management plane access).
    - Event Grid: 'Event Grid Data Sender' is already appropriately scoped.
    
    TODO before production:
    - Narrow Cosmos DB role to 'Cosmos DB Built-in Data Contributor' (data plane only)
    - Narrow Storage role based on actual read/write needs
    - Scope role assignments to specific resources, not resource groups
    - Add network restrictions (VNet integration, private endpoints)
    """
    if MANAGED_IDENTITY_CLIENT_ID:
        return ManagedIdentityCredential(client_id=MANAGED_IDENTITY_CLIENT_ID)
    return DefaultAzureCredential()


class BlobProcessor:
    """Handles reading and processing files from Azure Blob Storage."""

    def __init__(self, credential):
        self.blob_service_client = BlobServiceClient(
            account_url=STORAGE_ACCOUNT_URL,
            credential=credential
        )
        self.container_client = self.blob_service_client.get_container_client(
            STORAGE_CONTAINER_NAME
        )

    def read_blob(self, blob_name: str) -> bytes:
        """Read a blob's content."""
        blob_client = self.container_client.get_blob_client(blob_name)
        blob_data = blob_client.download_blob()
        return blob_data.readall()

    def process_file(self, blob_name: str) -> Dict[str, Any]:
        """
        Process a file from blob storage and return structured results.
        Customize this method based on your file processing needs.
        """
        logging.info(f"Processing blob: {blob_name}")

        raw_content = self.read_blob(blob_name)
        content_str = raw_content.decode("utf-8", errors="replace")

        # Example processing - customize for your use case
        result = {
            "blob_name": blob_name,
            "file_size_bytes": len(raw_content),
            "line_count": content_str.count("\n") + 1 if content_str else 0,
            "word_count": len(content_str.split()) if content_str else 0,
            "processed_at": datetime.datetime.utcnow().isoformat(),
            "status": "processed",
            "content_preview": content_str[:500] if content_str else "",
        }

        # Add content-type specific processing
        if blob_name.endswith(".json"):
            try:
                parsed = json.loads(content_str)
                result["record_count"] = len(parsed) if isinstance(parsed, list) else 1
                result["content_type"] = "json"
            except json.JSONDecodeError as e:
                result["status"] = "error"
                result["error_message"] = f"Invalid JSON: {str(e)}"
                result["content_type"] = "json"
        elif blob_name.endswith(".csv"):
            lines = content_str.strip().split("\n")
            result["record_count"] = max(0, len(lines) - 1)  # Exclude header
            result["content_type"] = "csv"
            if lines:
                result["columns"] = lines[0].split(",")
        else:
            result["content_type"] = "text"

        return result

    def mark_blob_processed(self, blob_name: str, success: bool = True):
        """
        Optionally move or tag the blob after processing.
        Uses Storage Blob Data Contributor permission.
        """
        blob_client = self.container_client.get_blob_client(blob_name)
        blob_client.set_blob_tags({
            "processed": str(success).lower(),
            "processed_at": datetime.datetime.utcnow().isoformat()
        })


class CosmosDBWriter:
    """Handles writing processing results to Cosmos DB."""

    def __init__(self, credential):
        self.client = CosmosClient(
            url=COSMOS_ENDPOINT,
            credential=credential
        )
        self.database = self.client.get_database_client(COSMOS_DATABASE_NAME)
        self.container = self.database.get_container_client(COSMOS_CONTAINER_NAME)

    def ensure_database_and_container(self):
        """
        Create database and container if they don't exist.
        NOTE: This requires 'Cosmos DB Account Contributor' role.
        For production, pre-create resources via IaC (Terraform/Bicep)
        and use 'Cosmos DB Built-in Data Contributor' instead.
        """
        try:
            self.client.create_database_if_not_exists(id=COSMOS_DATABASE_NAME)
            database = self.client.get_database_client(COSMOS_DATABASE_NAME)
            database.create_container_if_not_exists(
                id=COSMOS_CONTAINER_NAME,
                partition_key=PartitionKey(path="/blob_name"),
                offer_throughput=400
            )
            logging.info("Database and container ensured.")
        except Exception as e:
            logging.warning(f"Could not ensure DB/container (may already exist): {e}")

    def write_result(self, result: Dict[str, Any]) -> Dict[str, Any]:
        """Write a processing result to Cosmos DB."""
        # Ensure we have an id field for Cosmos DB
        if "id" not in result:
            result["id"] = f"{result.get('blob_name', 'unknown')}_{datetime.datetime.utcnow().strftime('%Y%m%d%H%M%S%f')}"

        # Sanitize the id (Cosmos DB doesn't allow '/' in id)
        result["id"] = result["id"].replace("/", "_").replace("\\", "_")

        logging.info(f"Writing result to Cosmos DB: {result['id']}")
        response = self.container.upsert_item(body=result)
        return response

    def write_error(self, blob_name: str, error: str) -> Dict[str, Any]:
        """Write an error record to Cosmos DB."""
        error_record = {
            "id": f"error_{blob_name}_{datetime.datetime.utcnow().strftime('%Y%m%d%H%M%S%f')}".replace("/", "_"),
            "blob_name": blob_name,
            "status": "error",
            "error_message": error,
            "processed_at": datetime.datetime.utcnow().isoformat(),
        }
        return self.container.upsert_item(body=error_record)


class EventGridNotifier:
    """Handles sending notifications via Event Grid."""

    def __init__(self, credential):
        self.client = EventGridPublisherClient(
            endpoint=EVENTGRID_ENDPOINT,
            credential=credential
        )

    def send_notification(
        self,
        event_type: str,
        subject: str,
        data: Dict[str, Any],
        source: str = "/azure/function/blob-processor"
    ):
        """Send a CloudEvent notification to Event Grid."""
        event = CloudEvent(
            type=event_type,
            source=source,
            subject=subject,
            data=data,
            time=datetime.datetime.utcnow(),
        )

        logging.info(f"Sending Event Grid notification: {event_type} - {subject}")
        self.client.send([event])

    def notify_processing_complete(self, result: Dict[str, Any]):
        """Send notification that file processing is complete."""
        self.send_notification(
            event_type="BlobProcessing.Completed",
            subject=f"/blobs/{result.get('blob_name', 'unknown')}",
            data={
                "blob_name": result.get("blob_name"),
                "status": result.get("status"),
                "processed_at": result.get("processed_at"),
                "file_size_bytes": result.get("file_size_bytes"),
                "cosmos_id": result.get("id"),
            }
        )

    def notify_processing_error(self, blob_name: str, error: str):
        """Send notification that file processing failed."""
        self.send_notification(
            event_type="BlobProcessing.Failed",
            subject=f"/blobs/{blob_name}",
            data={
                "blob_name": blob_name,
                "status": "error",
                "error_message": error,
                "failed_at": datetime.datetime.utcnow().isoformat(),
            }
        )


def process_single_blob(
    blob_name: str,
    blob_processor: BlobProcessor,
    cosmos_writer: CosmosDBWriter,
    notifier: EventGridNotifier
) -> Dict[str, Any]:
    """Process a single blob end-to-end."""
    try:
        # Step 1: Process the file from Blob Storage
        result = blob_processor.process_file(blob_name)

        # Step 2: Write results to Cosmos DB
        cosmos_response = cosmos_writer.write_result(result)
        result["cosmos_id"] = cosmos_response.get("id")

        # Step 3: Send success notification via Event Grid
        notifier.notify_processing_complete(result)

        # Step 4: Mark blob as processed
        blob_processor.mark_blob_processed(blob_name, success=True)

        logging.info(f"Successfully processed blob: {blob_name}")
        return result

    except Exception as e:
        error_msg = f"Error processing blob {blob_name}: {str(e)}"
        logging.error(error_msg, exc_info=True)

        # Write error to Cosmos DB
        try:
            cosmos_writer.write_error(blob_name, str(e))
        except Exception as cosmos_err:
            logging.error(f"Failed to write error to Cosmos DB: {cosmos_err}")

        # Send error notification
        try:
            notifier.notify_processing_error(blob_name, str(e))
        except Exception as eg_err:
            logging.error(f"Failed to send error notification: {eg_err}")

        # Mark blob as failed
        try:
            blob_processor.mark_blob_processed(blob_name, success=False)
        except Exception:
            pass

        raise


