@app.route(route="process", methods=["POST"], auth_level=func.AuthLevel.FUNCTION)
def http_trigger_processor(req: func.HttpRequest) -> func.HttpResponse:
    """
    HTTP-triggered function to manually process a specific blob or batch of blobs.
    
    Request body:
    {
        "blob_name": "path/to/file.json"  // Single file
    }
    OR
    {
        "blob_names": ["file1.json", "file2.csv"]  // Batch
    }
    OR
    {
        "process_all": true  // Process all unprocessed blobs
    }
    """
    logging.info("HTTP trigger received for blob processing")

    try:
        req_body = req.get_json()
    except ValueError:
        return func.HttpResponse(
            json.dumps({"error": "Invalid JSON in request body"}),
            status_code=400,
            mimetype="application/json"
        )

    credential = get_credential()
    blob_processor = BlobProcessor(credential)
    cosmos_writer = CosmosDBWriter(credential)
    notifier = EventGridNotifier(credential)

    # Ensure Cosmos DB resources exist
    cosmos_writer.ensure_database_and_container()

    results = []
    errors = []

    if "blob_name" in req_body:
        # Process single blob
        blob_names = [req_body["blob_name"]]
    elif "blob_names" in req_body:
        # Process batch
        blob_names = req_body["blob_names"]
    elif req_body.get("process_all"):
        # List and process all blobs in container
        blob_names = [
            blob.name
            for blob in blob_processor.container_client.list_blobs()
        ]
    else:
        return func.HttpResponse(
            json.dumps({"error": "Provide 'blob_name', 'blob_names', or 'process_all'"}),
            status_code=400,
            mimetype="application/json"
        )

    for blob_name in blob_names:
        try:
            result = process_single_blob(blob_name, blob_processor, cosmos_writer, notifier)
            results.append(result)
        except Exception as e:
            errors.append({"blob_name": blob_name, "error": str(e)})

    response = {
        "processed": len(results),
        "errors": len(errors),
        "results": results,
        "error_details": errors,
    }

    status_code = 200 if not errors else 207  # 207 Multi-Status if partial success
    return func.HttpResponse(
        json.dumps(response, default=str),
        status_code=status_code,
        mimetype="application/json"
    )


